            //enviar un evento para notificar de la tarea disponible
            mproducer.sendMessages(ts);

            //guardar los detalles de la tarea solicitada.
            fpers.getMapaProductosSolicitados().put(this.codigoTareaTF.getText(), ts);

        } catch (AmqpException ex) {
            Logger.getLogger(MainFrame.class.getName()).log(Level.SEVERE, null, ex);
            JOptionPane.showInputDialog("Error:"+ex.getLocalizedMessage());
        }
    }//GEN-LAST:event_botonEnvioActionPerformed

    private void codigoTareaTFActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_codigoTareaTFActionPerformed
        showProductResult(codigoTareaTF.getText().trim());
    }//GEN-LAST:event_codigoTareaTFActionPerformed

    public void notifyOffersUpdated() {
        SwingUtilities.invokeLater(() -> showProductResult(codigoTareaTF.getText().trim()));
    }

    private void showProductResult(String code) {
        if (resultadosTA == null) {
            return;
        }
        if (code.isEmpty() || fpers == null) {
            resultadosTA.setText("Ingrese un codigo para consultar resultados.");
            return;
        }

        int offers = fpers.getMapaOfertasRecibidas().getOrDefault(code, 0);
        String winner = fpers.getMapaOferentesAsignados().getOrDefault(code, "Sin ofertas");
        Integer bestAmount = fpers.getMapaMontosAsignados().get(code);

        if (offers < MAX_OFFERS_PER_PRODUCT) {
            resultadosTA.setText(
                    "Producto: " + code
                            + "\nOfertas recibidas: " + offers + "/" + MAX_OFFERS_PER_PRODUCT
                            + "\nEstado: esperando las primeras " + MAX_OFFERS_PER_PRODUCT + " propuestas"
            );
            return;
        }

        resultadosTA.setText(
                "Oferta ganadora\n"
                        + "Producto: " + code
                        + "\nComprador: " + winner
                        + "\nMonto: " + (bestAmount == null ? "N/A" : bestAmount)
        );
    }

